document.addEventListener('DOMContentLoaded', function() {
    // State management
    let state = {
        tooltipQuestionId: null,
        savingQuestionId: null
    };

    // Initialize event listeners
    initializeEventListeners();

    function initializeEventListeners() {
        // Response button clicks
        const responseButtons = document.querySelectorAll('.response-button');
        responseButtons.forEach(button => {
            button.addEventListener('click', handleResponseClick);
        });

        // Dealbreaker tooltip interactions
        const dealbreakerIndicators = document.querySelectorAll('.dealbreaker-indicator');
        dealbreakerIndicators.forEach(indicator => {
            indicator.addEventListener('mouseenter', handleDealbreakerMouseEnter);
            indicator.addEventListener('mouseleave', handleDealbreakerMouseLeave);
            indicator.addEventListener('focus', handleDealbreakerMouseEnter);
            indicator.addEventListener('blur', handleDealbreakerMouseLeave);
        });
    }

    function handleResponseClick(event) {
        const button = event.currentTarget;
        const questionRow = button.closest('.question-row');
        const questionId = getQuestionIdFromRow(questionRow);
        const response = button.textContent.trim();
        const isDealbreaker = questionRow.querySelector('.dealbreaker-indicator') !== null;

        // Get current response state
        const yesButton = questionRow.querySelector('.response-button-yes');
        const noButton = questionRow.querySelector('.response-button-no');
        const currentResponse = yesButton.classList.contains('selected') ? 'Yes' : 
                              noButton.classList.contains('selected') ? 'No' : null;

        // Check if this is a toggle off (clicking same response again)
        const isToggleOff = (currentResponse === response);
        const finalResponse = isToggleOff ? null : response;

        // Check if this triggers dealbreaker (assuming 'No' is dealbreaker value for demo)
        const triggersDisqualification = !isToggleOff && isDealbreaker && response === 'No';

        // Show confirmation for dealbreaker responses
        if (triggersDisqualification) {
            const confirmed = confirm(
                '⚠️ WARNING: This response will automatically disqualify the lead.\n\n' +
                'The lead status will be changed to "Disqualified".\n\n' +
                'Do you want to proceed?'
            );

            if (!confirmed) {
                return; // User cancelled
            }
        }

        // Update button states
        updateButtonStates(questionRow, finalResponse);

        // Simulate saving with loading state
        simulateSaveResponse(questionRow, finalResponse);
    }

    function updateButtonStates(questionRow, response) {
        const yesButton = questionRow.querySelector('.response-button-yes');
        const noButton = questionRow.querySelector('.response-button-no');

        // Remove selected class from both buttons
        yesButton.classList.remove('selected');
        noButton.classList.remove('selected');
        yesButton.setAttribute('aria-pressed', 'false');
        noButton.setAttribute('aria-pressed', 'false');

        // Add selected class to the chosen response
        if (response === 'Yes') {
            yesButton.classList.add('selected');
            yesButton.setAttribute('aria-pressed', 'true');
        } else if (response === 'No') {
            noButton.classList.add('selected');
            noButton.setAttribute('aria-pressed', 'true');
        }
    }

    function simulateSaveResponse(questionRow, response) {
        const buttons = questionRow.querySelectorAll('.response-button');

        // Show loading state
        buttons.forEach(button => {
            button.disabled = true;
            if (button.classList.contains('selected')) {
                button.innerHTML = '<div class="slds-spinner slds-spinner_x-small button-spinner"><div class="slds-spinner__dot-a"></div><div class="slds-spinner__dot-b"></div></div>';
            }
        });

        // Simulate API call delay
        setTimeout(() => {
            // Restore button states
            buttons.forEach(button => {
                button.disabled = false;
                if (button.classList.contains('response-button-yes')) {
                    button.textContent = 'Yes';
                } else {
                    button.textContent = 'No';
                }
            });

            // Update progress if needed
            updateProgress();

            // Show success message
            showToast('Success', 'Response saved successfully', 'success');
        }, 1000);
    }

    function updateProgress() {
        const questionRows = document.querySelectorAll('.question-row');
        let answeredCount = 0;

        questionRows.forEach(row => {
            const hasSelected = row.querySelector('.response-button.selected');
            if (hasSelected) {
                answeredCount++;
            }
        });

        const totalQuestions = questionRows.length;
        const progressPercentage = Math.round((answeredCount / totalQuestions) * 100);

        // Update progress bar
        const progressFill = document.querySelector('.progress-bar-fill');
        const progressBar = document.querySelector('.progress-bar-container');
        if (progressFill && progressBar) {
            progressFill.style.width = progressPercentage + '%';
            progressBar.setAttribute('aria-valuenow', progressPercentage);
        }

        // Update progress text
        const progressValue = document.querySelector('.metric-card .metric-value');
        const progressSubtitle = document.querySelector('.metric-card .metric-subtitle');
        if (progressValue && progressSubtitle) {
            progressValue.textContent = progressPercentage + '%';
            progressSubtitle.textContent = answeredCount + ' of ' + totalQuestions + ' answered';
        }

        // Update legend
        const answeredLegend = document.querySelector('.legend-item .legend-text');
        const unansweredLegend = document.querySelectorAll('.legend-item .legend-text')[1];
        if (answeredLegend && unansweredLegend) {
            answeredLegend.textContent = 'Answered (' + answeredCount + ')';
            unansweredLegend.textContent = 'Unanswered (' + (totalQuestions - answeredCount) + ')';
        }
    }

    function handleDealbreakerMouseEnter(event) {
        const indicator = event.currentTarget;
        const questionRow = indicator.closest('.question-row');
        const questionId = getQuestionIdFromRow(questionRow);

        // Create and show tooltip
        const tooltip = document.createElement('div');
        tooltip.className = 'dealbreaker-tooltip';
        tooltip.textContent = '⚠️ Answering "No" will automatically disqualify this lead.';

        indicator.appendChild(tooltip);
        state.tooltipQuestionId = questionId;
    }

    function handleDealbreakerMouseLeave(event) {
        const indicator = event.currentTarget;
        const tooltip = indicator.querySelector('.dealbreaker-tooltip');

        if (tooltip) {
            tooltip.remove();
        }

        state.tooltipQuestionId = null;
    }

    function getQuestionIdFromRow(questionRow) {
        const badge = questionRow.querySelector('.badge-number');
        return badge ? badge.textContent.trim() : '1';
    }

    function showToast(title, message, variant) {
        // Simple toast notification
        const toast = document.createElement('div');
        toast.className = 'toast-notification toast-' + variant;
        toast.innerHTML = '<strong>' + title + '</strong>: ' + message;

        // Style the toast
        Object.assign(toast.style, {
            position: 'fixed',
            top: '20px',
            right: '20px',
            padding: '12px 16px',
            borderRadius: '4px',
            color: 'white',
            fontWeight: '500',
            fontSize: '14px',
            zIndex: '10000',
            maxWidth: '300px',
            boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)'
        });

        if (variant === 'success') {
            toast.style.backgroundColor = '#2e844a';
        } else if (variant === 'error') {
            toast.style.backgroundColor = '#ea001e';
        } else if (variant === 'warning') {
            toast.style.backgroundColor = '#fe9339';
        }

        document.body.appendChild(toast);

        // Auto remove after 3 seconds
        setTimeout(() => {
            if (toast.parentNode) {
                toast.parentNode.removeChild(toast);
            }
        }, 3000);
    }
});

